import { Link } from "react-router-dom";

function Card({character, onClose }) {
  const {id, name, species,gender, image} = character
  return (
    <div>
      <button
        onClick={() => {
          onClose(id);
        }}
      >
        X
      </button>
      <Link to={`/detail/${id}`}><h2>{name}</h2></Link>
      <h2>{species}</h2>
      <h2>{gender}</h2>
      <img src={image} alt={name} />
    </div>
  );
}

export default Card;
